import React, { useEffect, useState } from 'react';

/* ─── Design tokens (insforge.dev palette) ─── */
const T = {
  bg:       '#FFFFFF',
  bg2:      '#F8FAFC',
  bgDark:   '#0F172A',
  card:     '#FFFFFF',
  border:   '#E2E8F0',
  border2:  '#CBD5E1',
  blue:     '#2563EB',
  blueDk:   '#1D4ED8',
  blueLt:   '#EFF6FF',
  blueStr:  '#DBEAFE',
  text:     '#0F172A',
  text2:    '#475569',
  text3:    '#94A3B8',
  green:    '#10B981',
  purple:   '#8B5CF6',
  red:      '#EF4444',
  amber:    '#F59E0B',
};

/* ─── Pentagon logo SVG (adapted: navy + blue for light bg) ─── */
const PentagonLogo = ({ size = 32, className = '' }) => (
  <svg
    width={size} height={size}
    viewBox="0 0 1023 977"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
  >
    <path d="M1022.52 373.339C1021.96 372.826 1021.43 372.662 1020.91 372.849C952.332 397.256 883.755 421.662 815.182 446.069C815.175 446.069 815.165 446.069 815.152 446.069L813.942 446.119L355.892 113.329C355.837 113.291 355.792 113.24 355.762 113.181C355.731 113.122 355.715 113.055 355.715 112.988C355.715 112.921 355.731 112.854 355.762 112.793C355.792 112.732 355.837 112.68 355.892 112.639L510.772 0.108917C510.873 0.0363731 510.996 -0.00173594 511.121 6.07308e-05C511.247 0.0018574 511.37 0.0434618 511.472 0.118911C529.505 13.2856 698.222 135.869 1017.62 367.869C1020.3 369.816 1021.92 371.036 1022.47 371.529C1022.89 371.896 1022.91 372.499 1022.52 373.339Z" fill={T.bgDark}/>
    <path d="M612.422 504.079L415.752 576.149C372.365 546.522 329.145 517.002 286.092 487.589C259.552 469.462 232.819 451.019 205.892 432.259C179.252 413.692 152.602 395.125 125.942 376.559L54.1621 326.559L209.062 215.459C209.316 215.275 209.621 215.176 209.935 215.176C210.249 215.176 210.556 215.275 210.812 215.459L612.422 504.079Z" fill={T.bgDark}/>
    <path d="M54.1621 326.559L125.942 376.559L294.232 916.569L273.442 976.189L189.202 976.149C189.094 976.149 188.99 976.116 188.904 976.054C188.817 975.993 188.754 975.907 188.722 975.809L0.0420414 366.449C-0.0162491 366.256 -0.0138681 366.051 0.0488316 365.861C0.111531 365.671 0.231459 365.506 0.392048 365.389L54.1621 326.559Z" fill="url(#pg_grad)"/>
    <path d="M612.421 504.079C612.468 506.719 612.085 508.646 611.271 509.859C607.945 517.606 605.398 525.519 603.631 533.599L459.441 975.729C459.399 975.868 459.312 975.99 459.195 976.076C459.078 976.163 458.937 976.209 458.791 976.209L273.441 976.189L294.231 916.569C294.578 916.289 294.835 915.916 295.001 915.449C335.255 802.876 375.511 690.306 415.771 577.739C416.158 576.666 416.151 576.136 415.751 576.149L612.421 504.079Z" fill={T.blue}/>
    <path d="M960.793 563.233L827.393 973.609C827.337 973.781 827.229 973.93 827.084 974.036C826.938 974.142 826.763 974.199 826.583 974.199H642.673C642.615 974.199 642.558 974.186 642.507 974.159C642.456 974.133 642.411 974.094 642.378 974.047C642.345 974 642.323 973.946 642.315 973.889C642.307 973.832 642.314 973.773 642.333 973.719L813.942 446.119L815.152 446.069H815.183C869.944 426.578 924.709 407.088 979.475 387.597L979.5 387.5L1023 372L960.793 563.233Z" fill={T.blue}/>
    <defs>
      <linearGradient id="pg_grad" x1="147.116" y1="326.559" x2="147.116" y2="976.189" gradientUnits="userSpaceOnUse">
        <stop stopColor={T.blue}/>
        <stop offset="1" stopColor={T.blueDk}/>
      </linearGradient>
    </defs>
  </svg>
);

/* ─── Scroll-reveal ─── */
function useReveal() {
  useEffect(() => {
    const obs = new IntersectionObserver(
      entries => entries.forEach(e => { if (e.isIntersecting) e.target.classList.add('visible'); }),
      { threshold: 0.1 }
    );
    document.querySelectorAll('.reveal').forEach(el => obs.observe(el));
    return () => obs.disconnect();
  }, []);
}

/* ─── Shared atoms ─── */
const Label = ({ children, dark }) => (
  <p className="font-mono text-[11px] font-semibold tracking-[0.2em] uppercase mb-4"
    style={{ color: dark ? 'rgba(255,255,255,0.4)' : T.blue }}>
    {children}
  </p>
);

const Wrap = ({ id, children, bg = T.bg, className = '' }) => (
  <section id={id} className={`py-24 sm:py-32 ${className}`} style={{ backgroundColor: bg }}>
    <div className="max-w-6xl mx-auto px-6 sm:px-10">{children}</div>
  </section>
);

/* ─── Inline code block (insforge-style dark terminal on light page) ─── */
const Terminal = ({ lines, filename = 'agent.ts' }) => {
  const [copied, setCopied] = useState(false);
  const raw = lines.map(l => (typeof l === 'string' ? l : l.raw || '')).join('\n');
  return (
    <div className="rounded-xl overflow-hidden border shadow-sm" style={{ backgroundColor: '#0F172A', borderColor: T.border }}>
      <div className="flex items-center justify-between px-4 py-2.5 border-b" style={{ borderColor: 'rgba(255,255,255,0.07)', backgroundColor: '#0B1220' }}>
        <div className="flex items-center gap-2">
          <span className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: '#EF4444', opacity: 0.7 }} />
          <span className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: '#F59E0B', opacity: 0.7 }} />
          <span className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: '#10B981', opacity: 0.7 }} />
          <span className="font-mono text-[11px] ml-2" style={{ color: 'rgba(255,255,255,0.35)' }}>{filename}</span>
        </div>
        <button onClick={() => { navigator.clipboard?.writeText(raw); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
          className="font-mono text-[11px] px-2.5 py-1 rounded-md transition-colors"
          style={{ color: copied ? T.green : 'rgba(255,255,255,0.35)', border: '1px solid rgba(255,255,255,0.1)' }}>
          {copied ? '✓ copied' : 'copy'}
        </button>
      </div>
      <div className="px-5 py-4 code-block overflow-x-auto">
        {lines.map((line, i) => (
          <div key={i} className="flex gap-4">
            <span className="select-none text-right w-4 flex-shrink-0 opacity-25" style={{ color: 'rgba(255,255,255,0.5)', fontSize: 11 }}>{i + 1}</span>
            <span>{typeof line === 'string' ? <span style={{ color: 'rgba(255,255,255,0.55)' }}>{line}</span> : line.jsx}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

/* ─── Install pill (insforge hero CTA style) ─── */
const InstallPill = ({ cmd = 'npm install glassmem' }) => {
  const [copied, setCopied] = useState(false);
  return (
    <button
      onClick={() => { navigator.clipboard?.writeText(cmd); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
      className="inline-flex items-center gap-3 px-5 py-3 rounded-xl border transition-all font-mono text-[13px] font-medium group"
      style={{ backgroundColor: T.bg2, borderColor: T.border, color: T.text }}
      onMouseEnter={e => { e.currentTarget.style.borderColor = T.blue; e.currentTarget.style.backgroundColor = T.blueLt; }}
      onMouseLeave={e => { e.currentTarget.style.borderColor = T.border; e.currentTarget.style.backgroundColor = T.bg2; }}
    >
      <span style={{ color: T.blue, opacity: 0.7 }}>$</span>
      <span>{cmd}</span>
      <span className="ml-2 text-[11px] px-1.5 py-0.5 rounded-md transition-colors"
        style={{ backgroundColor: copied ? T.green + '22' : T.border, color: copied ? T.green : T.text3 }}>
        {copied ? '✓' : '⌘C'}
      </span>
    </button>
  );
};

/* ═══════════════════════════════ NAVBAR ═══════════════════════════════ */
const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 16);
    window.addEventListener('scroll', h);
    return () => window.removeEventListener('scroll', h);
  }, []);
  const go = id => { setOpen(false); document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' }); };
  const links = [['Product', 'solution'], ['Docs', 'docs'], ['Pricing', 'pricing'], ['Blog', '']];
  return (
    <header className="fixed top-0 left-0 right-0 z-50 transition-all duration-200"
      style={{ backgroundColor: scrolled ? 'rgba(255,255,255,0.95)' : T.bg, borderBottom: `1px solid ${scrolled ? T.border : 'transparent'}`, backdropFilter: scrolled ? 'blur(12px)' : 'none' }}>
      <nav className="max-w-6xl mx-auto px-6 sm:px-10">
        <div className="flex items-center justify-between h-16">
          {/* Logo */}
          <div className="flex items-center gap-2.5">
            <PentagonLogo size={28} />
            <span className="font-bold text-[15px] tracking-[-0.02em]" style={{ color: T.text }}>
              GlassMem<span style={{ color: T.blue }}>.ai</span>
            </span>
          </div>
          {/* Desktop */}
          <div className="hidden md:flex items-center gap-1">
            {links.map(([label, id]) => (
              <button key={label} onClick={() => id && go(id)}
                className="text-[13px] px-3 py-1.5 rounded-lg font-medium transition-colors"
                style={{ color: T.text2 }}
                onMouseEnter={e => { e.currentTarget.style.color = T.text; e.currentTarget.style.backgroundColor = T.bg2; }}
                onMouseLeave={e => { e.currentTarget.style.color = T.text2; e.currentTarget.style.backgroundColor = 'transparent'; }}>
                {label}
              </button>
            ))}
            <div className="w-px h-4 mx-2" style={{ backgroundColor: T.border }} />
            <button onClick={() => go('cta')} className="btn-primary inline-flex items-center gap-1.5 px-4 py-2 text-[13px]">
              Get started <span className="opacity-60">→</span>
            </button>
          </div>
          {/* Mobile toggle */}
          <button className="md:hidden text-[20px]" style={{ color: T.text2 }} onClick={() => setOpen(!open)}>
            {open ? '✕' : '☰'}
          </button>
        </div>
        {open && (
          <div className="md:hidden border-t py-3 space-y-1" style={{ borderColor: T.border }}>
            {links.map(([label, id]) => (
              <button key={label} onClick={() => id && go(id)} className="block w-full text-left px-3 py-2.5 rounded-lg text-[14px]" style={{ color: T.text2 }}>{label}</button>
            ))}
            <button onClick={() => go('cta')} className="btn-primary block w-full px-3 py-2.5 text-left text-[14px] mt-2">Get started →</button>
          </div>
        )}
      </nav>
    </header>
  );
};

/* ═══════════════════════════════ HERO ═══════════════════════════════ */
const Hero = () => (
  <section className="relative pt-32 pb-20 overflow-hidden dot-grid" style={{ backgroundColor: T.bg }}>
    {/* Fade bottom of dot grid */}
    <div className="pointer-events-none absolute bottom-0 left-0 right-0 h-32"
      style={{ background: `linear-gradient(to bottom, transparent, ${T.bg})` }} />
    {/* Subtle blue radial top center */}
    <div className="pointer-events-none absolute -top-40 left-1/2 -translate-x-1/2 w-[700px] h-[500px] rounded-full"
      style={{ background: 'radial-gradient(ellipse, rgba(37,99,235,0.07) 0%, transparent 70%)' }} />

    <div className="max-w-6xl mx-auto px-6 sm:px-10 relative z-10">
      {/* Badge */}
      <div className="flex justify-center mb-8 fade-up">
        <div className="inline-flex items-center gap-2 px-3.5 py-1.5 rounded-full text-[12px] font-semibold border"
          style={{ backgroundColor: T.blueLt, borderColor: T.blueStr, color: T.blue }}>
          <span className="w-1.5 h-1.5 rounded-full pulse-dot" style={{ backgroundColor: T.green }} />
          Now in public beta — free to get started
        </div>
      </div>

      {/* Headline */}
      <div className="text-center mb-6 fade-up" style={{ animationDelay: '0.08s' }}>
        <h1 className="font-bold leading-[1.05] tracking-[-0.04em]"
          style={{ fontSize: 'clamp(40px, 7vw, 80px)', color: T.text }}>
          Memory infrastructure<br />
          <span style={{ color: T.blue }}>for AI agents.</span>
        </h1>
      </div>

      {/* Sub */}
      <p className="text-center text-[17px] sm:text-[19px] leading-relaxed max-w-2xl mx-auto mb-10 fade-up"
        style={{ color: T.text2, animationDelay: '0.14s' }}>
        Persistent, temporal, cross-session memory — shared across every agent, session, and user.
        No RAG pipelines. No vector tuning.
        <strong style={{ color: T.text }}> Three API calls.</strong>
      </p>

      {/* CTAs */}
      <div className="flex flex-col sm:flex-row items-center justify-center gap-4 mb-12 fade-up" style={{ animationDelay: '0.2s' }}>
        <button onClick={() => document.getElementById('cta')?.scrollIntoView({ behavior: 'smooth' })}
          className="btn-primary inline-flex items-center gap-2 px-6 py-3 text-[15px]">
          Start building free
          <span className="opacity-70">→</span>
        </button>
        <button onClick={() => document.getElementById('docs')?.scrollIntoView({ behavior: 'smooth' })}
          className="btn-secondary inline-flex items-center gap-2 px-6 py-3 text-[15px]">
          View docs
        </button>
      </div>

      {/* Install pill — insforge-style hero CTA */}
      <div className="flex justify-center mb-16 fade-up" style={{ animationDelay: '0.26s' }}>
        <InstallPill />
      </div>

      {/* Hero panel — two column */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 fade-up" style={{ animationDelay: '0.34s' }}>
        {/* Left: code snippet */}
        <Terminal filename="agent.ts" lines={[
          { raw: "import { GlassMem } from 'glassmem'", jsx: <span><span style={{ color: '#7DD3FC' }}>import</span><span style={{ color: 'rgba(255,255,255,0.55)' }}> {'{ GlassMem }'} </span><span style={{ color: '#7DD3FC' }}>from</span><span style={{ color: '#86EFAC' }}> 'glassmem'</span></span> },
          { raw: '', jsx: <span /> },
          { raw: "const memory = new GlassMem({ apiKey })", jsx: <span><span style={{ color: '#7DD3FC' }}>const</span><span style={{ color: 'rgba(255,255,255,0.55)' }}> memory = </span><span style={{ color: '#34D399' }}>new</span><span style={{ color: T.blue }}> GlassMem</span><span style={{ color: 'rgba(255,255,255,0.55)' }}>{'({ apiKey })'}</span></span> },
          { raw: '', jsx: <span /> },
          { raw: "// remember what agents learn", jsx: <span style={{ color: 'rgba(255,255,255,0.3)' }}>// remember what agents learn</span> },
          { raw: "await memory.remember(userId, {", jsx: <span><span style={{ color: '#C084FC' }}>await</span><span style={{ color: 'rgba(255,255,255,0.55)' }}> memory.</span><span style={{ color: '#22D3EE' }}>remember</span><span style={{ color: 'rgba(255,255,255,0.55)' }}>(userId, {'{'}</span></span> },
          { raw: "  preference: 'Vegetarian',", jsx: <span><span style={{ color: 'rgba(255,255,255,0.35)' }}>{'  '}preference: </span><span style={{ color: '#86EFAC' }}>'Vegetarian'</span><span style={{ color: 'rgba(255,255,255,0.35)' }}>,</span></span> },
          { raw: "  expires: '7d'", jsx: <span><span style={{ color: 'rgba(255,255,255,0.35)' }}>{'  '}expires: </span><span style={{ color: '#86EFAC' }}>'7d'</span></span> },
          { raw: "})", jsx: <span style={{ color: 'rgba(255,255,255,0.55)' }}>{'})'};</span> },
          { raw: '', jsx: <span /> },
          { raw: "// recall before every inference", jsx: <span style={{ color: 'rgba(255,255,255,0.3)' }}>// recall before every inference</span> },
          { raw: "const ctx = await memory.recall(userId)", jsx: <span><span style={{ color: '#7DD3FC' }}>const</span><span style={{ color: 'rgba(255,255,255,0.55)' }}> ctx = </span><span style={{ color: '#C084FC' }}>await</span><span style={{ color: 'rgba(255,255,255,0.55)' }}> memory.</span><span style={{ color: '#22D3EE' }}>recall</span><span style={{ color: 'rgba(255,255,255,0.55)' }}>(userId)</span></span> },
          { raw: "// → { preference: 'Vegetarian', ... }", jsx: <span style={{ color: 'rgba(255,255,255,0.28)' }}>{"// → { preference: 'Vegetarian', ... }"}</span> },
        ]} />

        {/* Right: live memory stats panel */}
        <div className="rounded-xl border overflow-hidden" style={{ backgroundColor: T.bg2, borderColor: T.border }}>
          {/* Panel header */}
          <div className="flex items-center justify-between px-4 py-3 border-b bg-white" style={{ borderColor: T.border }}>
            <div className="flex items-center gap-2">
              <PentagonLogo size={16} />
              <span className="text-[12px] font-semibold" style={{ color: T.text }}>GlassMem Dashboard</span>
            </div>
            <span className="flex items-center gap-1.5 text-[11px] font-mono" style={{ color: T.green }}>
              <span className="w-1.5 h-1.5 rounded-full pulse-dot" style={{ backgroundColor: T.green }} />
              live
            </span>
          </div>

          {/* Stats row */}
          <div className="grid grid-cols-3 divide-x" style={{ divideColor: T.border, borderBottom: `1px solid ${T.border}` }}>
            {[['2,401', 'Memories'], ['18.7k', 'Recalls/day'], ['< 8ms', 'p99 latency']].map(([v, l]) => (
              <div key={l} className="px-4 py-4 bg-white">
                <p className="font-bold text-[22px] tracking-[-0.03em] stat-num">{v}</p>
                <p className="text-[11px] font-mono mt-0.5" style={{ color: T.text3 }}>{l}</p>
              </div>
            ))}
          </div>

          {/* Live event feed */}
          <div className="divide-y" style={{ divideColor: T.border }}>
            {[
              { icon: '🧠', label: 'memory.remember()', detail: 'user_8821 · preference saved', color: T.blue, time: '0.2s' },
              { icon: '⚡', label: 'memory.recall()', detail: 'user_4492 · 6 memories assembled', color: T.green, time: '1.1s' },
              { icon: '⏳', label: 'memory.expire()', detail: 'user_1130 · TTL 7d enforced', color: T.amber, time: '3.4s' },
              { icon: '🔗', label: 'cross-agent sync', detail: 'agent_A → agent_B context shared', color: T.purple, time: '5.8s' },
            ].map((ev, i) => (
              <div key={i} className="flex items-center gap-3 px-4 py-3 bg-white transition-colors"
                onMouseEnter={e => (e.currentTarget.style.backgroundColor = T.bg2)}
                onMouseLeave={e => (e.currentTarget.style.backgroundColor = T.bg)}>
                <span className="text-base flex-shrink-0">{ev.icon}</span>
                <div className="flex-1 min-w-0">
                  <p className="font-mono text-[12px] font-semibold" style={{ color: ev.color }}>{ev.label}</p>
                  <p className="text-[11px] truncate" style={{ color: T.text3 }}>{ev.detail}</p>
                </div>
                <span className="font-mono text-[10px] flex-shrink-0" style={{ color: T.text3 }}>{ev.time}s ago</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  </section>
);

/* ═══════════════════════════════ INTEGRATION STRIP ═══════════════════════════════ */
const INTEGRATIONS = ['OpenAI', 'Anthropic', 'LangChain', 'MCP Protocol', 'CrewAI', 'LlamaIndex', 'Claude Code', 'Cursor Agents', 'AutoGen', 'Local LLMs', 'OpenAI SDK', 'REST API'];
const IntegrationStrip = () => (
  <div className="border-y overflow-hidden relative py-4" style={{ borderColor: T.border, backgroundColor: T.bg2 }}>
    <div className="flex gap-0 scroll-strip">
      {[...INTEGRATIONS, ...INTEGRATIONS].map((name, i) => (
        <div key={i} className="flex-shrink-0 flex items-center gap-2.5 px-7 text-[13px] font-medium" style={{ color: T.text2 }}>
          <span className="w-1 h-1 rounded-full" style={{ backgroundColor: i % 3 === 0 ? T.blue : T.text3 }} />
          {name}
        </div>
      ))}
    </div>
    <div className="pointer-events-none absolute inset-y-0 left-0 w-20" style={{ background: `linear-gradient(to right, ${T.bg2}, transparent)` }} />
    <div className="pointer-events-none absolute inset-y-0 right-0 w-20" style={{ background: `linear-gradient(to left, ${T.bg2}, transparent)` }} />
  </div>
);

/* ═══════════════════════════════ PROBLEM ═══════════════════════════════ */
const PROBLEMS = [
  { n: '01', icon: '🐟', color: T.red, title: 'The Goldfish Effect', body: 'Agents forget everything between sessions. The fix — re-sending full chat histories — explodes token costs, adds latency, and breaks multi-turn workflows.', tags: ['Token blowout', 'Broken sessions', 'Repetition'] },
  { n: '02', icon: '🏝️', color: T.purple, title: 'Context Silos', body: 'Every agent learns in isolation. Your coding agent and research agent never share what they know. Users repeat themselves endlessly.', tags: ['Isolated memory', 'No cross-agent sync', 'Duplicate context'] },
  { n: '03', icon: '⏱️', color: T.amber, title: 'Temporal Blindness', body: 'Vector databases treat 2-year-old facts the same as yesterday\'s events. Agents retrieve stale context and confidently hallucinate outdated reality.', tags: ['Stale retrieval', 'No recency bias', 'Hallucinations'] },
];

const Problem = () => (
  <Wrap id="problem" bg={T.bg2}>
    <div className="text-center mb-14 reveal">
      <Label>// The Problem</Label>
      <h2 className="font-bold tracking-[-0.035em] leading-[1.08]" style={{ fontSize: 'clamp(32px,5vw,56px)', color: T.text }}>
        AI agents have a<br />memory problem.
      </h2>
      <p className="mt-4 text-[17px] max-w-xl mx-auto" style={{ color: T.text2 }}>
        Three root causes breaking 90% of production agent deployments.
      </p>
    </div>
    <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
      {PROBLEMS.map((p, i) => (
        <div key={p.n} className="reveal rounded-2xl p-6 border bg-white shadow-sm transition-all"
          style={{ borderColor: T.border, transitionDelay: `${i * 0.08}s` }}
          onMouseEnter={e => { e.currentTarget.style.borderColor = p.color + '66'; e.currentTarget.style.boxShadow = `0 8px 30px ${p.color}18`; }}
          onMouseLeave={e => { e.currentTarget.style.borderColor = T.border; e.currentTarget.style.boxShadow = '0 1px 3px rgba(15,23,42,0.04)'; }}>
